const input = $input.first().json;
const resumeText = String(input.text ?? '').trim();
const jobDescription = String(input.job_description ?? '').trim();
const targetRole = String(input.target_role ?? '').trim() || 'Not specified';

if (!resumeText) {
  throw new Error('No resume text was extracted. Use a text-based PDF; scanned PDFs require OCR.');
}
if (resumeText.length < 150) {
  throw new Error(`Extracted resume text is too short (${resumeText.length} characters).`);
}
if (jobDescription.length < 80) {
  throw new Error('Job description is too short for a meaningful comparison.');
}

return [{
  json: {
    ...input,
    input_valid: true,
    resume_text: resumeText,
    job_description: jobDescription,
    target_role: targetRole,
  },
}];

const raw = $input.first().json;
let a = raw.output ?? raw;
if (typeof a === 'string') {
  try { a = JSON.parse(a); } catch { throw new Error('Analysis output is not valid JSON.'); }
}

const list = value => Array.isArray(value) && value.length
  ? value.map(item => `- ${item}`).join('\n')
  : '- None detected';

const report = `# Resume Analysis Report

**Mode:** ${a.analysis_mode ?? 'openai'}  
**Candidate:** ${a.candidate_name ?? 'Not reliably detected'}  
**Target role:** ${a.target_role ?? 'Not specified'}  
**ATS-style score:** ${a.ats_score ?? 'N/A'}/100

## Summary

${a.professional_summary ?? ''}

## Matched skills

${list(a.matched_skills)}

## Missing or under-documented skills

${list(a.missing_skills)}

## Strengths

${list(a.strengths)}

## Weaknesses / resume gaps

${list(a.weaknesses)}

## Recommended actions

${list(a.recommended_actions)}

## Suggested interview questions

${list(a.interview_questions)}

---

*${a.disclaimer ?? 'AI-assisted heuristic review; verify all claims manually.'}*`;

return [{ json: { ...a, report_markdown: report } }];
